        self.flags.c = (_r >> 8) != 0;
        self.flags.z = self.reg.a == 0;
        self.flags.n = (self.reg.a >> 7) != 0;
        self.mem[sym::YCO] = self.reg.a;
        self.mem[sym::IMAGE] = 0x1b;
        self.mem[sym::OPACITY] = 0x01;
        self.reg.a = 0x02;
        self.flags.z = self.reg.a == 0;
        self.flags.n = (self.reg.a >> 7) != 0;
        self.addmid();
        return;
