    fn getobjid1(&mut self) {
        self.reg.a = self.mem[sym::inbuilder];
        self.flags.z = self.reg.a == 0;
        self.flags.n = (self.reg.a >> 7) != 0;
        if self.reg.a != 0x00 {
            self.getobjbldr();
            return;
        }
        self.mem[sym::state] = self.mem[((self.mem[sym::BlueSpec] as usize | (self.mem[sym::BlueSpec + 1] as usize) << 8) + self.reg.y as usize) & 0xffff];
        self.reg.a = self.mem[((self.mem[sym::BlueType] as usize | (self.mem[sym::BlueType + 1] as usize) << 8) + self.reg.y as usize) & 0xffff];
        self.flags.z = self.reg.a == 0;
        self.flags.n = (self.reg.a >> 7) != 0;
        self.reg.a &= 0x1f;
        match self.reg.a {
            0x06 => {
                self.reg.a = self.mem[sym::state];
                self.flags.z = self.reg.a == 0;
                self.flags.n = (self.reg.a >> 7) != 0;
                self.reg.x = self.reg.a;
                self.reg.a = self.mem[(sym::LINKMAP + self.reg.x as usize) & 0xffff];
                self.flags.z = self.reg.a == 0;
                self.flags.n = (self.reg.a >> 7) != 0;
                self.reg.a &= 0x1f;
                if self.reg.a < 0x02 {
                    self.reg.a = 0x06;  // plate up
                    self.flags.z = self.reg.a == 0;
                    self.flags.n = (self.reg.a >> 7) != 0;
                    return;
                }
                self.reg.a = 0x05;  // plate depressed
                self.flags.z = self.reg.a == 0;
                self.flags.n = (self.reg.a >> 7) != 0;
                return;
            }
            0x0f => {
                self.reg.a = self.mem[sym::state];
                self.flags.z = self.reg.a == 0;
                self.flags.n = (self.reg.a >> 7) != 0;
                self.reg.x = self.reg.a;
                self.reg.a = self.mem[(sym::LINKMAP + self.reg.x as usize) & 0xffff];
                self.flags.z = self.reg.a == 0;
                self.flags.n = (self.reg.a >> 7) != 0;
                self.reg.a &= 0x1f;
                if self.reg.a < 0x02 {
                    self.reg.a = 0x0f;
                    self.flags.z = self.reg.a == 0;
                    self.flags.n = (self.reg.a >> 7) != 0;
                    return;
                }
                self.mem[sym::state] = 0x00;
                self.reg.a = 0x01;  // depressed upp looks just like floor
                self.flags.z = self.reg.a == 0;
                self.flags.n = (self.reg.a >> 7) != 0;
                return;
            }
            _ => {}
        }
        return;
    }

